import { useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { addToCart, removeItem } from "./CartSlice";

function Milk() {
  const cart = useSelector((state) => state.cart);
  const dispatch = useDispatch();

  const handleAddToCart = (item) => {
    dispatch(addToCart({ ...item, id: 300 + item.id }));
  };

  const milkItems = [
    {
      id: 1,
      name: "Fresh Cow Milk",
      price: "60 RS",
      description: "Pure fresh cow milk, rich in calcium and protein.",
      image:
        "data:image/jpeg;base64,"
    },
    {
      id: 2,
      name: "Paneer (250g)",
      price: "140 RS",
      description: "Soft and fresh cottage cheese made from premium milk.",
      image:
        "data:image/jpeg;base64,"
    },
    {
      id: 3,
      name: "Chocolate Milk",
      price: "80 RS",
      description: "Creamy milk blended with rich chocolate flavor.",
      image:
        "data:image/jpeg;base64,"
    },
    {
      id: 4,
      name: "Strawberry Milkshake",
      price: "120 RS",
      description: "Thick and refreshing milkshake with real strawberry taste.",
      image:
        "data:image/jpeg;base64,"
    },
    {
      id: 5,
      name: "Ice Cream",
      price: "140 RS",
      description: "Amul Chocochip Ice Cream is a popular, creamy frozen dessert featuring rich chocolate-flavored ice cream packed with crunchy, real chocolate chips.",
      image:
        "https://encrypted-tbn2.gstatic.com/shopping?q=tbn:ANd9GcQEO7MtXL9e_mero0yuwXnjqqAoMGn2r7CbzccWNjVxGRW6SDoo_ByRegSAbgYE0YRZpZYcrOllBwJ9yuXLZi6DQCCfRWdO"
    },
    {
      id: 6,
      name: "Lassi",
      price: "70 RS",
      description: "Traditional sweet lassi made with fresh curd and milk.",
      image:
        "data:image/jpeg;base64,"
    }
  ];

  return (
    <div style={{ padding: "20px" }}>
      <h2>Milk Items</h2>

      <h3>Cart Items: {cart.length}</h3>

      <div style={{ display: "flex", gap: "20px", flexWrap: "wrap" }}>
        {milkItems.map((item) => (
          <div
            key={item.id}
            style={{
              border: "1px solid #0584af",
              borderRadius: "10px",
              width: "250px",
              padding: "10px",
              textAlign: "center"
            }}
          >
            <img
              src={item.image}
              alt={item.name}
              style={{ width: "100%", borderRadius: "10px", height: "170px", objectFit: "cover" }}
            />

            <h3>{item.name}</h3>
            <h4>{item.price}</h4>
            <p>{item.description}</p>

            <button
              onClick={() => handleAddToCart(item)}
              style={{
                marginTop: "10px",
                padding: "8px",
                backgroundColor: "green",
                color: "white",
                border: "none",
                borderRadius: "5px",
                cursor: "pointer"
              }}
            >
              Add to Cart
            </button>
          </div>
        ))}
      </div>

      <h2 style={{ marginTop: "40px" }}>Cart</h2>

      {cart.length === 0 ? (
        <p>No items in cart</p>
      ) : (
        cart.map((item, index) => (
          <div
            key={index}
            style={{
              border: "1px solid gray",
              margin: "10px 0",
              padding: "10px",
              borderRadius: "5px",
              display: "flex",
              justifyContent: "space-between"
            }}
          >
            <span>
              {item.name} - {item.price}
            </span>

            <button
              onClick={() => dispatch(removeItem(item.id))}
              style={{
                backgroundColor: "red",
                color: "white",
                border: "none",
                padding: "5px 10px",
                borderRadius: "5px",
                cursor: "pointer"
              }}
            >
              Remove
            </button>
          </div>
        ))
      )}
    </div>
  );
}

export default Milk;
